import manifest from '@/data/page-sources.generated.json';

// Per-page "Sources" section, driven by the network claims ledger.
// The manifest is generated by docs/claims/gen-sources.mjs — do not hand-edit it.
// Renders nothing for routes with no ledger-verified claims.

type SourceClaim = { id: string; claim: string; status: string; sources: string[] };

const ROUTES = (manifest.routes ?? {}) as Record<string, SourceClaim[]>;
const SITE_ORIGIN = 'https://screferralbonus.com';

function sourceLabel(url: string): string {
  try {
    const u = new URL(url);
    if (u.hostname.startsWith('support.')) return 'RSI Support';
    if (u.hostname.includes('gamespress')) return 'CIG Press Release';
    if (u.hostname.includes('robertsspaceindustries')) {
      if (u.pathname.includes('/comm-link/')) return 'RSI Comm-Link';
      if (u.pathname.includes('referral-program')) return 'RSI Referral Program';
      if (u.pathname.includes('funding')) return 'RSI Funding Tracker';
      if (u.pathname.includes('squadron42')) return 'RSI — Squadron 42';
      return 'RSI Official';
    }
    return u.hostname.replace(/^www\./, '');
  } catch {
    return 'Source';
  }
}

export function PageSources({ route }: { route: string }) {
  const claims = ROUTES[route];
  if (!claims || claims.length === 0) return null;

  const canonical = route === '/' ? `${SITE_ORIGIN}/` : `${SITE_ORIGIN}${route}`;
  const citationUrls = Array.from(new Set(claims.flatMap((c) => c.sources)));
  const jsonLd = {
    '@context': 'https://schema.org',
    '@type': 'WebPage',
    '@id': canonical,
    url: canonical,
    citation: citationUrls.map((url) => ({ '@type': 'CreativeWork', url })),
  };

  return (
    <section className="mx-auto max-w-4xl px-5 sm:px-8 pb-20" aria-labelledby="page-sources-heading">
      <div className="mx-auto max-w-3xl border-t border-platinum/10 pt-12">
        <h2
          id="page-sources-heading"
          className="font-display text-2xl sm:text-3xl font-bold uppercase tracking-tight text-platinum"
        >
          Sources
        </h2>
        <p className="mt-3 text-sm text-platinum/70 leading-relaxed">
          Every factual claim on this page is verified against official Cloud Imperium Games
          sources. Figures are checked against the primary RSI page linked below — not
          third-party trackers.
        </p>
        <ul className="mt-6 space-y-4">
          {claims.map((c) => (
            <li key={c.id} className="border border-platinum/10 bg-charcoalMid/40 p-4">
              <p className="text-sm text-platinum">{c.claim}</p>
              <div className="mt-2 flex flex-wrap gap-x-4 gap-y-1">
                {c.sources.map((url) => (
                  <a
                    key={url}
                    href={url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="font-mono text-xs text-gold hover:underline"
                  >
                    {sourceLabel(url)} ↗
                  </a>
                ))}
              </div>
            </li>
          ))}
        </ul>
      </div>

      <script
        type="application/ld+json"
        // eslint-disable-next-line react/no-danger
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
      />
    </section>
  );
}
